import { UnionFind } from './UnionFind';

function solve(c, connections, queries) {
    // Initialize Union-Find structure for the grid
    const uf = new UnionFind(c);

    // Process connections to build the grid
    for (const [u, v] of connections) {
        uf.union(u, v);
    }

    // For each node, store the root of its set
    const rootMap = new Array(c + 1).fill(0).map((_, i) => uf.find(i));

    // For each root, store the minimum node in its set
    const minNodeMap = new Map();
    for (let i = 1; i <= c; i++) {
        const root = uf.find(i);
        if (!minNodeMap.has(root)) {
            minNodeMap.set(root, i);
        }
    }

    // Process queries
    const result = [];

    for (const [type, x] of queries) {
        if (type === 1) {
            // Maintenance check query
            if (uf.find(x) === x) {
                // x is online and is the root of its set
                result.push(x);
            } else {
                // Find the root of x's set
                const root = uf.find(x);
                // Get the minimum node in the set
                const minNode = minNodeMap.get(root);
                if (minNode !== undefined) {
                    result.push(minNode);
                } else {
                    result.push(-1);
                }
            }
        } else {
            // Offline query
            uf.disconnect(x);
        }
    }

    return result;
}

class UnionFind {
    constructor(size) {
        this.parent = Array(size + 1).fill(0).map((_, i) => i);
        this.rank = Array(size + 1).fill(0);
    }

    find(x) {
        if (this.parent[x] !== x) {
            this.parent[x] = this.find(this.parent[x]);
        }
        return this.parent[x];
    }

    union(x, y) {
        const xRoot = this.find(x);
        const yRoot = this.find(y);

        if (xRoot === yRoot) {
            return;
        }

        if (this.rank[xRoot] < this.rank[yRoot]) {
            this.parent[xRoot] = yRoot;
        } else {
            this.parent[yRoot] = xRoot;
            if (this.rank[xRoot] === this.rank[yRoot]) {
                this.rank[xRoot]++;
            }
        }
    }

    disconnect(x) {
        // In this problem, we don't need to actually disconnect the nodes,
        // but we need to mark them as offline. However, since the grid structure
        // is fixed, we can't directly modify the Union-Find structure to reflect
        // offline nodes. Therefore, we'll track the online status separately.
